// app/admin/AdminDashboardClient.jsx
"use client";
import { useState, useRef } from "react";
import { 
  LayoutDashboard, Map, Users, FileText, Settings, 
  Menu, Tent, Euro, CheckCircle2, Clock, X, ChevronDown, 
  UploadCloud, Image as ImageIcon, Mail, Phone, Calendar, Search
} from "lucide-react";

// ⚡ 1. On importe notre nouveau composant de layout
import AdminLayout from "./AdminLayout"; 

// ... (GARDE TES CONSTANTES "C", "MENU" ET TES FONCTIONS StatCard, CustomSelect, etc. ICI) ...

/* ── DASHBOARD PRINCIPAL ── */
export default function AdminDashboardClient({ stats, inscriptions, sejours, clients }) {
  const [activeTab, setActiveTab] = useState("dashboard");
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);

  return (
    // ⚡ 2. On encapsule tout dans le AdminLayout
    <AdminLayout 
      sidebarOpen={sidebarOpen} 
      setSidebarOpen={setSidebarOpen} 
      activeTab={activeTab} 
      setActiveTab={setActiveTab}
      MENU={MENU}
      C={C}
    >
      {/* ⚪ CONTENU DU DASHBOARD */}
      <div style={{ flex: 1, overflowY: "auto", padding: "40px 32px" }}>
        <div style={{ maxWidth: "1200px", margin: "0 auto" }}>
          
          {/* TITRE DYNAMIQUE & BARRE DE RECHERCHE */}
          <div style={{ marginBottom: "40px", display: "flex", justifyContent: "space-between", alignItems: "flex-end", flexWrap: "wrap", gap: "20px" }}>
            <div>
              <h1 style={{ fontSize: "32px", fontWeight: 900, color: C.teal, marginBottom: "8px", letterSpacing: "-0.5px" }}>
                {activeTab === "dashboard" && "Bonjour, l'équipe 👋"}
                {activeTab === "sejours" && "Gestion des Séjours 🏕️"}
                {activeTab === "clients" && "Répertoire Clients 👥"}
                {activeTab === "inscriptions" && "Suivi Inscriptions ✍️"}
                {activeTab === "settings" && "Paramètres ⚙️"}
              </h1>
              <p style={{ fontSize: "14px", color: C.gray, fontWeight: 500 }}>Données synchronisées avec Neon en temps réel.</p>
            </div>

            <div style={{ display: "flex", alignItems: "center", gap: "16px" }}>
              <div style={{ position: "relative", width: "320px" }}>
                <Search size={18} color={C.gray} style={{ position: "absolute", left: "16px", top: "50%", transform: "translateY(-50%)" }} />
                <input 
                  type="text" 
                  placeholder="Chercher une inscription, un séjour..." 
                  style={{ width: "100%", padding: "14px 16px 14px 44px", borderRadius: "14px", border: `1px solid ${C.lightGray}`, background: C.white, fontSize: "13px", fontWeight: 600, color: C.teal, outline: "none", boxShadow: "0 2px 12px rgba(17,76,90,0.03)", transition: "border-color 0.2s" }}
                  onFocus={(e) => e.target.style.borderColor = C.yellow}
                  onBlur={(e) => e.target.style.borderColor = C.lightGray}
                />
              </div>

              {activeTab === "sejours" && (
                <button onClick={() => setIsModalOpen(true)} style={{ background: C.teal, color: C.white, border: "none", padding: "14px 28px", borderRadius: "14px", fontSize: "13px", fontWeight: 800, cursor: "pointer", boxShadow: "0 4px 12px rgba(17,76,90,0.2)", transition: "transform 0.2s", whiteSpace: "nowrap" }}
                onMouseOver={(e) => e.currentTarget.style.transform = "translateY(-2px)"}
                onMouseOut={(e) => e.currentTarget.style.transform = "translateY(0)"}>
                  + Nouveau Séjour
                </button>
              )}
            </div>
          </div>

          {/* SWITCHER DE CONTENU */}
          {activeTab === "dashboard" && (
            <>
              <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(240px, 1fr))", gap: "24px", marginBottom: "40px" }}>
                <StatCard title="Inscriptions" value={stats?.inscriptionsTotal || 0} icon={FileText} color={C.saffron} />
                <StatCard title="Chiffre d'affaires" value={`${stats?.ca || 0} €`} icon={Euro} color={"#10b981"} />
                <StatCard title="Séjours actifs" value={stats?.sejoursActifs || 0} icon={Tent} color={C.teal} />
                <StatCard title="Familles" value={stats?.familles || 0} icon={Users} color={C.yellow} />
              </div>
              <TableInscriptions data={inscriptions} />
            </>
          )}

          {activeTab === "sejours" && <TableSejours data={sejours} />}
          
          {activeTab === "clients" && (
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(300px, 1fr))", gap: "20px" }}>
              {clients?.map(c => (
                <div key={c.id} style={{ background: C.white, padding: "24px", borderRadius: "20px", boxShadow: "0 4px 12px rgba(0,0,0,0.03)" }}>
                  <h3 style={{ color: C.teal, fontWeight: 800, marginBottom: "12px" }}>{c.nom} {c.prenom}</h3>
                  <div style={{ display: "flex", flexDirection: "column", gap: "8px", fontSize: "13px", color: C.gray }}>
                     <span style={{ display: "flex", alignItems: "center", gap: "8px" }}><Mail size={14}/> {c.email}</span>
                     <span style={{ display: "flex", alignItems: "center", gap: "8px" }}><Phone size={14}/> {c.telephone}</span>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* MODALE */}
      {isModalOpen && <ModalCreerSejour setIsModalOpen={setIsModalOpen} isSubmitting={isSubmitting} setIsSubmitting={setIsSubmitting} />}
    </AdminLayout>
  );
}